### Response:
fn fibonacci(n: u32) -> u32 {
    let mut a = 0;
    let mut b = 1;
    let mut c = 0;

    for _ in 0..n {
        c = a + b;
        a = b;
        b = c;
    }
    return a
}

fn main() {
    for n in 0..10 {
        println!("{} ", fibonacci(n));
    }
}

