### Instruction:
Create a C# program to evaluate a simple expression taken as a string.

### Response:
using System;

public class Program
{
 public static void Main()
 {
  string expression = "2+5*3";

  int result = EvaluateExpression(expression);

  Console.WriteLine(result);
 }

 public static int EvaluateExpression(string expression)
 {
  int result = 0;
  int currentNumber = 0;
  char operation = '+';

  foreach (char c in expression)
  {
   if (char.IsDigit(c))
   {
    currentNumber = currentNumber * 10 + (c - '0');
    continue;
   }

   switch (operation)
   {
    case '+':
     result += currentNumber;
     break;
    case '-':
     result -= currentNumber;
     break;
    case '*':
     result *= currentNumber;
     break;
    case '/':
     result /= currentNumber;
     break;
   }

   currentNumber = 0;
   operation = c;
  }

  return result + currentNumber;
 }
}

### Instruction:
Develop an Android application for a recipe database. This application should include models for Recipe (with fields for the name, ingredients, and instructions) and a RecipeAdapter, which converts the Recipes into a format that can be displayed in a ListView.

### Response:
public class Recipe {
 private String name;
 private String[] ingredients;
 private String[] instructions;

 public Recipe(String name, String[] ingredients, String[] instructions) {
  this.name = name;
  this.ingredients = ingredients;
  this.instructions = instructions;
 }

 // Getters and setters
 public String getName() {
  return name;
 }
 public void setName(String name) {
  this.name = name;
 }
 public String[] getIngredients() {
  return ingredients;
 }
 public void setIngredients(String[] ingredients) {
  this.ingredients = ingredients;
 }
 public String[] getInstructions() {
  return instructions;
 }
 public void setInstructions(String[] instructions) {
  this.instructions = instructions;
 }
}

public class RecipeAdapter extends ArrayAdapter<Recipe> {
 public RecipeAdapter(@NonNull Context context, List<Recipe> recipes) {
  super(context, 0, recipes); 
 }

 @Override
 public View getView(int position, @Nullable View convertView, @NonNull ViewGroup parent) {
  // Get the data item for this position 
  Recipe recipe = getItem(position);

  // Check if an existing view is being reused, otherwise inflate the view
  if (convertView == null) {
   convertView = LayoutInflater.from(getContext()).inflate(R.layout.list_item, parent, false);
  }

  // Lookup view for data population
  TextView tvName = (TextView) convertView.findViewById(R.id.list_item_name);
  TextView tvIngredients = (TextView) convertView.findViewById(R.id.list_item_ingredients);

  // Populate the data into the template view using the data object
  tvName.setText(recipe.getName());
  tvIngredients.setText(Arrays.toString(recipe.getIngredients()));

  // Return the completed view to render onscreen
  return convertView;
 }
}

