function getAge(currentDate, birthDate) {
    // get current date in milliseconds
    currentTime = Date.parse(currentDate);
    // get birthdate in milliseconds
    birthTime = Date.parse(birthDate);

    // get the difference between two dates in milliseconds
    differenceTime = currentTime - birthTime;

    // convert milliseconds to years
    differenceTime = differenceTime/1000/60/60/24/365.25;

    // return the age
    return Math.floor(differenceTime);
}

### Instruction:
Create a function in Java to validate a credit card number using the Luhn algorithm.

### Response:
public static boolean validateCardNumber(String creditCardNumber) {
  // Check if the length of the credit card number is valid
  if (creditCardNumber.length() != 16)
   return false;

  // Initialize variables
  int sum = 0;
  boolean alternate = false;

  // Iterate over every digit in the credit card number 
  for (int i = creditCardNumber.length() - 1; i >= 0; i--) {
   int n = Integer.parseInt(creditCardNumber.substring(i, i + 1));

   // Double every alternate digits 
   if (alternate)
    n *= 2;

   // Add the digits in the doubled value
   if (n > 9)
    n = (n % 10) + 1;

   // Add the double digit to the sum
   sum += n;
   alternate = !alternate;
  }

  // Return true if the sum is a multiple of 10
  return (sum % 10 == 0);
}

