   <Line
    data={chartData}
    width="600"
    height="400"
    options={{ 
     maintainAspectRatio: false,
     legend: {
      labels: {
       fontColor: 'black',
      },
     },
    }}
   />
  </div>
 );
}

export default StockChart;

