Create a function to compress a string using the Run-length encoding algorithm.

### Response:
function compressString(str) {
  let result = '';
  let letterCount = 0;
  for(let i = 0; i < str.length; i++) {
    letterCount += 1;
    if(i + 1 >= str.length || str[i] !== str[i + 1]) {
      result += `${str[i]}${letterCount}`;
      letterCount = 0;
    }
  }
  return result;
}

