Create a JavaScript function for validating a credit card number.

### Response:
// Function to validate a given credit card number 
function validateCreditCard(cardNumber) { 

    // Initializing the function 
    var nDigits = cardNumber.length;

    // Card number should be exactly 16 digits 
    if (nDigits == 16) { 
        // Verifying the starting two digits 
        var firstDigits = Number(cardNumber.substring(0, 2)); 

        // Restricted by the bank 
        if ((firstDigits >= 51) && (firstDigits <= 55)) { 
            // Variable $sum to store sum of alternating digits 
            var sum = 0; 
            var nDigit = 0;
            var isSecond = false; 

            // Iterate every other digits 
            for (var i = nDigits - 1; i >= 0; i--) { 

                // Convert the digit to number 
                var digit = Number(cardNumber.substring(i, i + 1)); 

                // Alternating digits 
                if (isSecond == true) { 
                    // Doubling every other digits 
                    nDigit = digit * 2; 

                    // Subtract 9 if the product is greater than 9 
                    if (nDigit >= 10)  
                        nDigit = nDigit - 9;  
                } 
                else { 
                    nDigit = digit; 
                } 

                // Summing the digits 
                sum = sum + nDigit; 

                // Toggling the boolean variable 
                isSecond = !isSecond; 
            } 

            // Validating the card number 
            if (sum % 10 == 0) { 
                return true; 
            } 
        } 
    } 

    return false; 
}

